        int numerator = 2 * i + 1;
        int denominator = i * i - 1;
        double term = ((i % 2 == 0) ? -1.0 : 1.0) * (double)numerator / denominator;
        sum += term;
    }

    printf("%.3f\n", sum);

    return 0;
}
